import"./style-C4px4kn2.js";const a="/api/auth",r=document.querySelector("#togglePassword"),o=document.querySelector("#password");r.addEventListener("click",function(){const t=o.getAttribute("type")==="password"?"text":"password";o.setAttribute("type",t),this.classList.toggle("fa-eye"),this.classList.toggle("fa-eye-slash")});document.getElementById("registerForm").addEventListener("submit",async t=>{t.preventDefault();const s={name:document.getElementById("name").value,email:document.getElementById("email").value,phone:document.getElementById("phone").value,password:document.getElementById("password").value,address:{street:document.getElementById("street").value,city:document.getElementById("city").value,state:document.getElementById("state").value,zip:document.getElementById("zip").value,country:document.getElementById("country").value}};try{const e=await fetch(`${a}/register`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(s)}),n=await e.json();e.ok?(alert("Registration successful! Please login."),window.location.href="login.html"):alert(n.message||"Registration failed")}catch(e){console.error("Error during registration:",e),alert("Something went wrong. Please try again.")}});
